        """Initialize the agent with the trained Q-table."""
        super().__init__()
        self.np_random = np.random.default_rng()
        
        # State discretization parameters
        self.position_bins = 32
        self.velocity_bins = 12
        self.wind_bins = 8
        
        # Q-table with learned values
        self.q_table = {}
        self._init_q_table()
    
